function validateData(headers, rows) {
    var isValid = true;
    rows.forEach(function(row) {
        headers.forEach(function(header) {
            if (header.required) {
                var value = row[header.colName];
                if (value === null || value === undefined || value === "") {
                    isValid = false;
                    return false;
                }
            }
        });
        if (!isValid) {
            return false;
        }
    });
    return isValid;
}

return validateData(this.headers_collection, this.block_rows_response);
